150→      throw new Error(`Project with id ${id} not found`);
151→    }
152→
153→    return prisma.project.update({
154→      where: { id },
155→      data: {
156→        ...data,
157→        updatedAt: new Date(),
158→      },
159→    });
160→  }
161→
162→  /**
163→   * Soft delete a project by setting deletedAt timestamp
164→   * Does NOT actually delete the record from database
165→   */
166→  async softDelete(id: string): Promise<Project> {
167→    // Verify project exists and not already deleted
168→    const existing = await this.findUnique(id);
169→    if (!existing) {
170→      throw new Error(`Project with id ${id} not found`);
171→    }
172→
173→    return prisma.project.update({
174→      where: { id },
175→      data: { deletedAt: new Date() },
176→    });
177→  }
178→
179→  /**
180→   * Count projects matching criteria (excluding soft-deleted)
181→   */
182→  async count(where?: Prisma.ProjectWhereInput): Promise<number> {
183→    return prisma.project.count({
184→      where: {
185→        ...where,
186→        deletedAt: null,
187→      },
188→    });
189→  }
190→
191→  /**
192→   * Create a project stage
193→   */
194→  async createStage(
195→    projectId: string,
196→    data: Omit<Prisma.ProjectStageUncheckedCreateInput, 'id' | 'projectId'>
197→  ): Promise<ProjectStage> {
198→    return prisma.projectStage.create({
199→      data: {
