214→    return prisma.projectStage.update({
215→      where: { id: stageId },
216→      data,
217→    });
218→  }
219→
220→  /**
221→   * Find stages for a project
222→   */
223→  async findStages(projectId: string): Promise<ProjectStage[]> {
224→    return prisma.projectStage.findMany({
225→      where: { projectId },
226→      orderBy: { order: 'asc' },
227→    });
228→  }
229→
230→  /**
231→   * Add a member to a project
232→   */
233→  async addMember(
234→    projectId: string,
235→    userId: string,
236→    role: string = 'member'
237→  ): Promise<ProjectMember> {
238→    return prisma.projectMember.create({
239→      data: {
240→        id: randomUUID(),
241→        projectId,
242→        userId,
243→        role,
244→        joinedAt: new Date(),
245→      },
246→    });
247→  }
248→
249→  /**
250→   * Remove a member from a project (sets leftAt timestamp)
251→   */
252→  async removeMember(projectId: string, userId: string): Promise<ProjectMember> {
253→    const member = await prisma.projectMember.findUnique({
254→      where: { projectId_userId: { projectId, userId } },
255→    });
256→
257→    if (!member) {
258→      throw new Error(`Member ${userId} not found in project ${projectId}`);
259→    }
260→
261→    return prisma.projectMember.update({
262→      where: { projectId_userId: { projectId, userId } },
263→      data: { leftAt: new Date() },
264→    });
265→  }
266→
267→  /**
268→   * Find members for a project
269→   */
270→  async findMembers(projectId: string): Promise<ProjectMember[]> {
271→    return prisma.projectMember.findMany({
272→      where: {
273→        projectId,
274→        leftAt: null, // Only active members
275→      },
276→      include: {
277→        User: {
278→          select: {
279→            id: true,
280→            name: true,
281→            email: true,
282→          },
283→        },
284→      },
285→    });
286→  }
287→}
