  4→ * TypeScript client for Project API with fetch wrapper.
  5→ * Provides typed methods for CRUD operations on projects.
  6→ */
  7→
  8→import type {
  9→  ProjectData,
 10→  ProjectStageData,
 11→  ProjectListParams,
 12→  ProjectCreateInput,
 13→  ProjectUpdateInput,
 14→  ProjectStageUpdateInput,
 15→  ApiListResponse,
 16→  ApiResponse,
 17→  ApiClientConfig,
 18→} from './types';
 19→import { ApiClientError, parseApiError, parseJson } from './shared';
 20→
 21→export { ApiClientError } from './shared';
 22→
 23→/**
 24→ * Default base URL for API requests
 25→ */
 26→const DEFAULT_BASE_URL = '/api';
 27→
 28→/**
 29→ * Project API Client
 30→ *
 31→ * Provides typed methods for Project CRUD operations.
 32→ */
 33→export class ProjectApiClient {
 34→  private baseUrl: string;
 35→  private fetchFn: typeof globalThis.fetch;
 36→  private defaultHeaders: Record<string, string>;
 37→
 38→  constructor(config: ApiClientConfig = {}) {
 39→    this.baseUrl = config.baseUrl ?? DEFAULT_BASE_URL;
 40→    this.fetchFn = config.fetch ?? fetch;
 41→    this.defaultHeaders = {
 42→      'Content-Type': 'application/json',
 43→      ...config.headers,
 44→    };
 45→  }
 46→
 47→  /**
 48→   * Build full URL for endpoint
 49→   */
 50→  private url(path: string, params?: Record<string, string | undefined>): string {
 51→    const fullUrl = `${this.baseUrl}${path}`;
 52→
 53→    if (params) {
 54→      const searchParams = new URLSearchParams();
 55→      for (const [key, value] of Object.entries(params)) {
 56→        if (value !== undefined) {
 57→          searchParams.append(key, value);
 58→        }
 59→      }
 60→      const queryString = searchParams.toString();
 61→      if (queryString) {
 62→        return `${fullUrl}?${queryString}`;
 63→      }
 64→    }
 65→
 66→    return fullUrl;
 67→  }
 68→
 69→  /**
 70→   * GET /api/projects
 71→   *
 72→   * List all projects with optional filtering.
 73→   */
 74→  async getProjects(params?: ProjectListParams): Promise<ApiListResponse<ProjectData>> {
 75→    const response = await this.fetchFn(
 76→      this.url('/projects', {
 77→        status: params?.status,
 78→        managerId: params?.managerId,
 79→        contactId: params?.contactId,
 80→        dealId: params?.dealId,
 81→        skip: params?.skip?.toString(),
 82→        take: params?.take?.toString(),
 83→      }),
 84→      {
 85→        headers: this.defaultHeaders,
 86→      }
 87→    );
 88→
 89→    if (!response.ok) {
 90→      return parseApiError(response);
 91→    }
 92→
 93→    return parseJson<ApiListResponse<ProjectData>>(response);
 94→  }
 95→
 96→  /**
